import React from 'react';
import { YesNo, MaritalStatus } from '../types';

interface ToggleGroupProps {
  label: string;
  name: string;
  value: string;
  options: { label: string; value: string }[];
  onChange: (value: string) => void;
  required?: boolean;
}

export const ToggleGroup: React.FC<ToggleGroupProps> = ({ label, value, options, onChange, required }) => {
  return (
    <div className="flex flex-col gap-2 w-full">
      <label className="text-sm font-semibold text-gray-600 uppercase tracking-wide ml-1">
        {label} {required && <span className="text-pink-500">*</span>}
      </label>
      <div className="flex p-1 bg-gray-100 rounded-xl w-full">
        {options.map((option) => {
          const isActive = value === option.value;
          return (
            <button
              key={option.value}
              type="button"
              onClick={() => onChange(option.value)}
              className={`
                flex-1 py-2 text-sm font-medium rounded-lg transition-all duration-300
                ${isActive 
                  ? 'bg-white text-pink-600 shadow-md ring-1 ring-pink-100' 
                  : 'text-gray-500 hover:text-gray-700 hover:bg-gray-200/50'
                }
              `}
            >
              {option.label}
            </button>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { BioFormData, FormErrors, MaritalStatus, YesNo } from './types';
import { TEAM_MEMBERS } from './constants';
import { Input } from './components/Input';
import { Select } from './components/Select';
import { ToggleGroup } from './components/ToggleGroup';
import { submitToGoogleSheet } from './services/sheetService';

const App: React.FC = () => {
  const [formData, setFormData] = useState<BioFormData>({
    firstName: '',
    idNumber: '',
    passportNumber: '',
    taxNumber: '',
    hasDriversLicense: YesNo.No,
    hasCar: YesNo.No,
    carName: '',
    maritalStatus: MaritalStatus.Single,
  });

  const [errors, setErrors] = useState<FormErrors>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    let isValid = true;

    if (!formData.firstName) {
      newErrors.firstName = 'Please select your name.';
      isValid = false;
    }

    // ID Validation (13 digits)
    if (!/^\d{13}$/.test(formData.idNumber)) {
      newErrors.idNumber = 'ID must be exactly 13 digits.';
      isValid = false;
    }

    // Tax Validation (10 digits)
    if (!/^\d{10}$/.test(formData.taxNumber)) {
      newErrors.taxNumber = 'Tax number must be exactly 10 digits.';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    // Clear error for this field
    if (errors[name as keyof FormErrors]) {
      setErrors(prev => ({ ...prev, [name]: undefined }));
    }
  };

  const handleToggleChange = (name: keyof BioFormData, value: string) => {
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    setIsSubmitting(true);
    const success = await submitToGoogleSheet(formData);

    if (success) {
      setSubmitted(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      alert("Failed to submit data. Please try again.");
    }
    setIsSubmitting(false);
  };

  const handleReset = () => {
    setFormData({
      firstName: '',
      idNumber: '',
      passportNumber: '',
      taxNumber: '',
      hasDriversLicense: YesNo.No,
      hasCar: YesNo.No,
      carName: '',
      maritalStatus: MaritalStatus.Single,
    });
    setSubmitted(false);
    setErrors({});
  };

  if (submitted) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl p-10 text-center animate-[fadeIn_0.5s_ease-out]">
          <div className="w-20 h-20 bg-pink-100 text-pink-500 rounded-full flex items-center justify-center mx-auto mb-6">
            <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
          </div>
          <h2 className="text-3xl font-bold text-gray-800 mb-4">Success!</h2>
          <p className="text-gray-500 mb-8">Your bio data has been securely transmitted to the Central Bio Data repository.</p>
          <button 
            onClick={handleReset}
            className="w-full py-3 bg-pink-500 hover:bg-pink-600 text-white font-bold rounded-xl transition-all shadow-lg shadow-pink-500/30"
          >
            Submit Another Response
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-12 px-4 sm:px-6 lg:px-8 font-sans">
      <div className="max-w-2xl mx-auto">
        {/* Header */}
        <div className="text-center mb-12">
          <h1 className="text-4xl md:text-5xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-pink-600 to-purple-600 mb-4 tracking-tight">
            Central Bio Data
          </h1>
          <p className="text-gray-500 text-lg">Secure Employee Information Portal</p>
        </div>

        {/* Form Container */}
        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-gray-200/50 p-8 md:p-12 relative overflow-hidden border border-white">
          {/* Decorative Elements */}
          <div className="absolute top-0 right-0 -mr-16 -mt-16 w-64 h-64 bg-pink-50 rounded-full blur-3xl opacity-50 pointer-events-none"></div>
          <div className="absolute bottom-0 left-0 -ml-16 -mb-16 w-64 h-64 bg-purple-50 rounded-full blur-3xl opacity-50 pointer-events-none"></div>

          <form onSubmit={handleSubmit} className="relative z-10 space-y-8">

            {/* Section 1: Identity */}
            <div className="space-y-6">
              <h3 className="text-lg font-bold text-gray-400 uppercase tracking-widest border-b border-gray-100 pb-2 mb-4">
                Personal Identification
              </h3>

              <Select
                label="First Name"
                name="firstName"
                value={formData.firstName}
                onChange={handleChange}
                options={TEAM_MEMBERS}
                placeholder="Select your name"
                required
                error={errors.firstName}
              />

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <Input
                  label="ID Number"
                  name="idNumber"
                  value={formData.idNumber}
                  onChange={handleChange}
                  placeholder="13 Digit SA ID"
                  required
                  maxLength={13}
                  error={errors.idNumber}
                />
                <Input
                  label="Tax Number"
                  name="taxNumber"
                  value={formData.taxNumber}
                  onChange={handleChange}
                  placeholder="10 Digit Tax No."
                  required
                  maxLength={10}
                  error={errors.taxNumber}
                />
              </div>

              <Input
                label="Passport Number"
                name="passportNumber"
                value={formData.passportNumber}
                onChange={handleChange}
                placeholder="Optional"
              />
            </div>

            {/* Section 2: Details */}
            <div className="space-y-6">
              <h3 className="text-lg font-bold text-gray-400 uppercase tracking-widest border-b border-gray-100 pb-2 mb-4 pt-4">
                Status & Assets
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <ToggleGroup
                  label="Marital Status"
                  name="maritalStatus"
                  value={formData.maritalStatus}
                  options={[
                    { label: 'Single', value: MaritalStatus.Single },
                    { label: 'Married', value: MaritalStatus.Married }
                  ]}
                  onChange={(val) => handleToggleChange('maritalStatus', val)}
                  required
                />
                 <ToggleGroup
                  label="Drivers License"
                  name="hasDriversLicense"
                  value={formData.hasDriversLicense}
                  options={[
                    { label: 'Yes', value: YesNo.Yes },
                    { label: 'No', value: YesNo.No }
                  ]}
                  onChange={(val) => handleToggleChange('hasDriversLicense', val)}
                  required
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 items-start">
                <ToggleGroup
                  label="Do you have a Car?"
                  name="hasCar"
                  value={formData.hasCar}
                  options={[
                    { label: 'Yes', value: YesNo.Yes },
                    { label: 'No', value: YesNo.No }
                  ]}
                  onChange={(val) => handleToggleChange('hasCar', val)}
                  required
                />

                {/* Conditionally show Car Name input with animation */}
                <div className={`transition-all duration-500 ease-in-out overflow-hidden ${formData.hasCar === YesNo.Yes ? 'max-h-24 opacity-100' : 'max-h-0 opacity-0'}`}>
                   <Input
                    label="Car Name"
                    name="carName"
                    value={formData.carName}
                    onChange={handleChange}
                    placeholder="e.g. Toyota Corolla"
                  />
                </div>
              </div>
            </div>

            {/* Footer / Submit */}
            <div className="pt-8">
              <button
                type="submit"
                disabled={isSubmitting}
                className={`
                  w-full py-4 rounded-xl font-bold text-lg tracking-wide text-white
                  transition-all duration-300 transform shadow-xl shadow-pink-500/20
                  ${isSubmitting 
                    ? 'bg-gray-300 cursor-not-allowed' 
                    : 'bg-gradient-to-r from-pink-500 to-rose-500 hover:scale-[1.01] hover:shadow-pink-500/40'
                  }
                `}
              >
                {isSubmitting ? (
                  <span className="flex items-center justify-center gap-2">
                    <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Processing...
                  </span>
                ) : (
                  "Submit Bio Data"
                )}
              </button>
              <p className="text-center text-gray-400 text-xs mt-4">
                Secure 256-bit Encrypted Submission
              </p>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default App;

import { BioFormData } from '../types';
import { GOOGLE_SCRIPT_URL } from '../constants';

export const submitToGoogleSheet = async (data: BioFormData): Promise<boolean> => {
  // Check if the URL is still the placeholder
  if (GOOGLE_SCRIPT_URL.includes("YOUR_SCRIPT_ID")) {
    console.warn("Development Mode: Submitting to placeholder. Data will not be saved to a real sheet.");
    console.log("Payload:", data);
    // Simulate success for demo purposes
    return new Promise((resolve) => setTimeout(() => resolve(true), 1500));
  }

  try {
    // We use 'no-cors' mode because Google Apps Script Web Apps do not support 
    // CORS headers for standard browser fetch requests easily. 
    // We send as 'text/plain' to prevent the browser from sending a preflight OPTIONS request.
    await fetch(GOOGLE_SCRIPT_URL, {
      method: 'POST',
      body: JSON.stringify(data),
      mode: 'no-cors',
      headers: {
        'Content-Type': 'text/plain',
      },
    });

    // With 'no-cors', we receive an opaque response and cannot check response.ok.
    // We assume success if the network request didn't throw an error.
    return true;
  } catch (error) {
    console.error("Submission error:", error);
    return false;
  }
};

import { BioFormData } from '../types';
import { GOOGLE_SCRIPT_URL } from '../constants';

export const submitToGoogleSheet = async (data: BioFormData): Promise<boolean> => {
  // Check if the URL is still the placeholder or if in dev mode
  if (!GOOGLE_SCRIPT_URL || GOOGLE_SCRIPT_URL.includes("YOUR_SCRIPT_ID")) {
    console.warn("Development Mode: Submitting to placeholder. Data will not be saved to a real sheet.");
    console.log("Payload:", data);
    return new Promise((resolve) => setTimeout(() => resolve(true), 1500));
  }

  try {
    // We use 'no-cors' mode. 
    // We do NOT set explicit Content-Type headers here.
    // By default, fetch with a string body will send as 'text/plain;charset=UTF-8'
    // which is exactly what Google Apps Script expects for e.postData.contents.
    await fetch(GOOGLE_SCRIPT_URL, {
      method: 'POST',
      body: JSON.stringify(data),
      mode: 'no-cors',
    });

    // In 'no-cors' mode, we cannot check response.ok or status.
    // If the network request didn't throw (e.g. DNS error, connection refused), we assume it reached Google.
    return true;
  } catch (error) {
    console.error("Submission error:", error);
    return false;
  }
};

import React, { useState } from 'react';
import { BioFormData, FormErrors, MaritalStatus, YesNo } from './types';
import { TEAM_MEMBERS } from './constants';
import { Input } from './components/Input';
import { Select } from './components/Select';
import { ToggleGroup } from './components/ToggleGroup';
import { submitToGoogleSheet } from './services/sheetService';

const App: React.FC = () => {
  const [formData, setFormData] = useState<BioFormData>({
    firstName: '',
    idNumber: '',
    passportNumber: '',
    taxNumber: '',
    hasDriversLicense: YesNo.No,
    hasCar: YesNo.No,
    carName: '',
    maritalStatus: MaritalStatus.Single,
  });

  const [errors, setErrors] = useState<FormErrors>({});
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    let isValid = true;

    if (!formData.firstName) {
      newErrors.firstName = 'Please select your name.';
      isValid = false;
    }

    // ID Validation (13 digits)
    if (!/^\d{13}$/.test(formData.idNumber)) {
      newErrors.idNumber = 'ID must be exactly 13 digits.';
      isValid = false;
    }

    // Tax Validation (10 digits)
    if (!/^\d{10}$/.test(formData.taxNumber)) {
      newErrors.taxNumber = 'Tax number must be exactly 10 digits.';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    // Clear error for this field
    if (errors[name as keyof FormErrors]) {
      setErrors(prev => ({ ...prev, [name]: undefined }));
    }
    if (submitError) setSubmitError(null);
  };

  const handleToggleChange = (name: keyof BioFormData, value: string) => {
    setFormData(prev => ({ ...prev, [name]: value }));
    if (submitError) setSubmitError(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) {
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return;
    }

    setIsSubmitting(true);
    setSubmitError(null);

    const success = await submitToGoogleSheet(formData);

    if (success) {
      setSubmitted(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      setSubmitError("Failed to connect to the database. Please check your internet connection and try again.");
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
    setIsSubmitting(false);
  };

  const handleReset = () => {
    setFormData({
      firstName: '',
      idNumber: '',
      passportNumber: '',
      taxNumber: '',
      hasDriversLicense: YesNo.No,
      hasCar: YesNo.No,
      carName: '',
      maritalStatus: MaritalStatus.Single,
    });
    setSubmitted(false);
    setErrors({});
    setSubmitError(null);
  };

  if (submitted) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl p-10 text-center animate-[fadeIn_0.5s_ease-out]">
          <div className="w-20 h-20 bg-pink-100 text-pink-500 rounded-full flex items-center justify-center mx-auto mb-6">
            <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
          </div>
          <h2 className="text-3xl font-bold text-gray-800 mb-4">Success!</h2>
          <p className="text-gray-500 mb-8">Your bio data has been securely transmitted to the Central Bio Data repository.</p>
          <button 
            onClick={handleReset}
            className="w-full py-3 bg-pink-500 hover:bg-pink-600 text-white font-bold rounded-xl transition-all shadow-lg shadow-pink-500/30"
          >
            Submit Another Response
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-12 px-4 sm:px-6 lg:px-8 font-sans">
      <div className="max-w-2xl mx-auto">
        {/* Header */}
        <div className="text-center mb-12">
          <h1 className="text-4xl md:text-5xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-pink-600 to-purple-600 mb-4 tracking-tight">
            Central Bio Data
          </h1>
          <p className="text-gray-500 text-lg">Secure Employee Information Portal</p>
        </div>

        {/* Error Notification */}
        {submitError && (
          <div className="mb-8 p-4 bg-red-50 border-l-4 border-red-500 rounded-r-xl shadow-sm animate-[shake_0.5s_ease-in-out]">
            <div className="flex">
              <div className="flex-shrink-0">
                <svg className="h-5 w-5 text-red-500" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                </svg>
              </div>
              <div className="ml-3">
                <p className="text-sm text-red-700 font-medium">
                  {submitError}
                </p>
              </div>
            </div>
          </div>
        )}

        {/* Form Container */}
        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-gray-200/50 p-8 md:p-12 relative overflow-hidden border border-white">
