const App: React.FC = () => {
  const [formData, setFormData] = useState<BioFormData>({
    uifReferenceNumber: '',
    title: '',
    initial: '',
    names: '',
    surname: '',
    idType: IdType.SmartCard,
    identityNumber: '',
    contactDetails: '',
    passport: '',
    taxNumber: '',
    physicalAddressLine: '',
    suburb: '',
    city: '',
    postalCode: '',
    countryOfIssue: '',
    accountNumber: '',
    bankName: '',
    bankType: '',
    branchCode: '',
  });

  const [errors, setErrors] = useState<FormErrors>({});
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    let isValid = true;

    // Required Text Fields
    const requiredFields: (keyof BioFormData)[] = [
      'title', 'initial', 'names', 'surname', 'physicalAddressLine', 
      'suburb', 'city', 'countryOfIssue', 'bankName', 'bankType'
    ];

    requiredFields.forEach(field => {
      if (!formData[field]) {
        newErrors[field] = 'This field is required';
        isValid = false;
      }
    });

    // Identity Number (13 Digits)
    if (!/^\d{13}$/.test(formData.identityNumber)) {
      newErrors.identityNumber = 'Must be exactly 13 digits.';
      isValid = false;
    }

    // Contact Details (Starts with 27, 11 digits total)
    // Regex explanation: ^27 matches start, \d{9} matches 9 more digits
    if (!/^27\d{9}$/.test(formData.contactDetails)) {
      newErrors.contactDetails = 'Must be 11 digits and start with 27 (e.g. 27821234567).';
      isValid = false;
    }

    // Tax Number (10 digits)
    if (!/^\d{10}$/.test(formData.taxNumber)) {
      newErrors.taxNumber = 'Must be exactly 10 digits.';
      isValid = false;
    }

    // Postal Code (4 Digits)
    if (!/^\d{4}$/.test(formData.postalCode)) {
      newErrors.postalCode = 'Must be 4 digits.';
      isValid = false;
    }

    // Account Number (Numeric required)
    if (!/^\d+$/.test(formData.accountNumber)) {
      newErrors.accountNumber = 'Must contain only numbers.';
      isValid = false;
    }

    // Branch Code (Numeric required)
    if (!/^\d+$/.test(formData.branchCode)) {
      newErrors.branchCode = 'Must contain only numbers.';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    // Clear error for this field
    if (errors[name as keyof FormErrors]) {
      setErrors(prev => ({ ...prev, [name]: undefined }));
    }
    if (submitError) setSubmitError(null);
  };

  const handleToggleChange = (name: keyof BioFormData, value: string) => {
    setFormData(prev => ({ ...prev, [name]: value as any }));
    if (submitError) setSubmitError(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) {
      // Find the first error and scroll to it if possible, otherwise top
      window.scrollTo({ top: 0, behavior: 'smooth' });
      return;
    }

    setIsSubmitting(true);
    setSubmitError(null);

    const success = await submitToGoogleSheet(formData);

    if (success) {
      setSubmitted(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      setSubmitError("Failed to connect to the database. Please check your internet connection and try again.");
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
    setIsSubmitting(false);
  };

  const handleReset = () => {
    setFormData({
      uifReferenceNumber: '',
      title: '',
      initial: '',
      names: '',
      surname: '',
      idType: IdType.SmartCard,
      identityNumber: '',
      contactDetails: '',
      passport: '',
      taxNumber: '',
      physicalAddressLine: '',
      suburb: '',
      city: '',
      postalCode: '',
      countryOfIssue: '',
      accountNumber: '',
      bankName: '',
      bankType: '',
      branchCode: '',
    });
    setSubmitted(false);
    setErrors({});
    setSubmitError(null);
  };

  if (submitted) {
    return (
