import React from 'react';

interface ToggleGroupProps {
  label: string;
  name: string;
  value: string;
  options: { label: string; value: string }[];
  onChange: (value: string) => void;
  required?: boolean;
}

export const ToggleGroup: React.FC<ToggleGroupProps> = ({ label, value, options, onChange, required }) => {
  return (
    <div className="flex flex-col gap-2 w-full">
      <label className="text-sm font-semibold text-gray-600 uppercase tracking-wide ml-1">
        {label} {required && <span className="text-pink-500">*</span>}
      </label>
      <div className="flex p-1 bg-gray-100 rounded-xl w-full">
        {options.map((option) => {
          const isActive = value === option.value;
          return (
            <button
              key={option.value}
              type="button"
              onClick={() => onChange(option.value)}
              className={`
                flex-1 py-2 text-sm font-medium rounded-lg transition-all duration-300
                ${isActive 
                  ? 'bg-white text-pink-600 shadow-md ring-1 ring-pink-100' 
                  : 'text-gray-500 hover:text-gray-700 hover:bg-gray-200/50'
                }
              `}
            >
              {option.label}
            </button>
          );
        })}
      </div>
    </div>
  );
};

# Google Apps Script Setup for Central Bio Data

To connect this form to a Google Sheet, follow these steps:

1. Create a new Google Sheet.
2. Go to **Extensions** > **Apps Script**.
3. Delete any code in the editor and paste the code below.
4. Click **Deploy** > **New deployment**.
5. Click the "Select type" gear icon and select **Web app**.
6. Configuration:
   - **Description**: Central Bio Data Backend
   - **Execute as**: Me
   - **Who has access**: Anyone
7. Click **Deploy**.
8. Copy the **Web App URL**.
9. Paste this URL into your `constants.ts` file as `GOOGLE_SCRIPT_URL`.

## Code to Paste

```javascript
function doPost(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
    var rawData = e.postData.contents;
    var data = JSON.parse(rawData);

    // Define the headers you want in the sheet
    var headers = [
      "Timestamp",
      "UIF Reference Number",
      "Title",
      "Initial",
      "Names",
      "Surname",
      "ID Type",
      "Identity Number",
      "Contact Details",
      "Passport",
      "Tax Number",
      "Physical Address Line",
      "Suburb",
      "City",
      "Postal Code",
      "Country of Issue",
      "Bank Name",
      "Bank Type",
      "Account Number",
      "Branch Code"
    ];

    // Check if headers exist in the first row, if not, create them
    var range = sheet.getRange(1, 1, 1, headers.length);
    if (sheet.getLastRow() === 0) {
      range.setValues([headers]);
      range.setFontWeight("bold");
      range.setBackground("#fce7f3"); // Light pink background
