  const [errors, setErrors] = useState<FormErrors>({});
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const validate = (): boolean => {
    const newErrors: FormErrors = {};
    let isValid = true;

    // Required Text Fields
    const requiredFields: (keyof BioFormData)[] = [
      'title', 'initial', 'names', 'surname', 'physicalAddressLine', 
      'suburb', 'city', 'countryOfIssue', 'bankName', 'bankType'
    ];

    requiredFields.forEach(field => {
      if (!formData[field]) {
        newErrors[field] = 'This field is required';
        isValid = false;
      }
    });

    // Identity Number (13 Digits)
    if (!/^\d{13}$/.test(formData.identityNumber)) {
      newErrors.identityNumber = 'Must be exactly 13 digits.';
      isValid = false;
    }

    // Contact Details (Starts with 27, 11 digits total)
    // Regex explanation: ^27 matches start, \d{9} matches 9 more digits
    if (!/^27\d{9}$/.test(formData.contactDetails)) {
      newErrors.contactDetails = 'Must be 11 digits and start with 27 (e.g. 27821234567).';
      isValid = false;
    }

    // Tax Number (10 digits)
    if (!/^\d{10}$/.test(formData.taxNumber)) {
      newErrors.taxNumber = 'Must be exactly 10 digits.';
      isValid = false;
    }

    // Postal Code (4 Digits)
    if (!/^\d{4}$/.test(formData.postalCode)) {
      newErrors.postalCode = 'Must be 4 digits.';
      isValid = false;
    }

    // Account Number (Numeric required)
    if (!/^\d+$/.test(formData.accountNumber)) {
      newErrors.accountNumber = 'Must contain only numbers.';
      isValid = false;
    }

    // Branch Code (Numeric required)
    if (!/^\d+$/.test(formData.branchCode)) {
      newErrors.branchCode = 'Must contain only numbers.';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

