```javascript
function doPost(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    // 1. Log the event for debugging (View in 'Executions' tab)
    console.log("Received POST request");

    // Safety check for event object
    if (!e || !e.postData) {
      console.error("No postData received");
      return ContentService.createTextOutput(JSON.stringify({ "result": "error", "error": "No data" })).setMimeType(ContentService.MimeType.JSON);
    }

    var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();

    // 2. Parse Data
    // We use getDataAsString() because the React app sends "text/plain" to bypass CORS
    var rawData = e.postData.getDataAsString();
    console.log("Raw Data:", rawData);

    var data = JSON.parse(rawData);

    // Define the headers you want in the sheet
    var headers = [
      "Timestamp",
      "UIF Reference Number",
      "Title",
      "Initial",
      "Names",
      "Surname",
      "ID Type",
      "Identity Number",
      "Contact Details",
      "Passport",
      "Tax Number",
      "Physical Address Line",
      "Suburb",
      "City",
      "Postal Code",
      "Country of Issue",
      "Bank Name",
      "Bank Type",
      "Account Number",
      "Branch Code"
    ];

    // Check if headers exist in the first row, if not, create them
    var range = sheet.getRange(1, 1, 1, headers.length);
    if (sheet.getLastRow() === 0) {
      range.setValues([headers]);
      range.setFontWeight("bold");
      range.setBackground("#fce7f3"); // Light pink background
    }

    // Map the incoming JSON data to the headers order
    // We strictly format numbers as strings (using "'") to prevent Sheets from 
    // auto-formatting IDs or Phone numbers.
    var row = [
      new Date(),
      data.uifReferenceNumber || "",
      data.title || "",
      data.initial || "",
      data.names || "",
      data.surname || "",
      data.idType || "",
      "'" + (data.identityNumber || ""),
      "'" + (data.contactDetails || ""),
      data.passport || "",
      "'" + (data.taxNumber || ""),
      data.physicalAddressLine || "",
      data.suburb || "",
      data.city || "",
      "'" + (data.postalCode || ""),
      data.countryOfIssue || "",
      data.bankName || "",
      data.bankType || "",
      "'" + (data.accountNumber || ""),
      "'" + (data.branchCode || "")
    ];

    sheet.appendRow(row);
    console.log("Row appended successfully");

    return ContentService.createTextOutput(JSON.stringify({ "result": "success", "row": sheet.getLastRow() }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (e) {
    console.error("Error occurred:", e.toString());
    return ContentService.createTextOutput(JSON.stringify({ "result": "error", "error": e.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}
